#[AsApprovableAction(actionKey: 'billing.refunds.issue', label: 'Issue refund', description: 'Refunds money to the customer\u2019s original payment method. Refunds > $500 require manager approval; refunds > $5000 require director + compliance sign-off.')]
final class IssueRefundAction {
    public function __invoke(IssueRefundData $data, Invoice $invoice): Refund {
        /* ... */
    }

    public function approvalContext(IssueRefundData $data, Invoice $invoice): array {
        return [
            'invoice_id' => $invoice->id,
            'amount_cents' => $data->amount_cents,
            'currency' => $invoice->currency,
            'requester_role' => auth()->user()->getRoleNames()->first(),
            'is_chargeback' => $data->reason === 'chargeback',
        ];
    }

    public function approvalLabel(IssueRefundData $data, Invoice $invoice): string {
        return sprintf('Refund #%s for %s %s', $invoice->number, $data->amount_cents / 100, $invoice->currency);
    }
}

